import Foundation

/// Baked at build time so an install is verifiable on-device (More > About).
/// Regenerated by the build wrapper before each xcodebuild.
enum BuildStamp {
  static let commit = "79cffd0"
  static let commitCount = 57
  static let builtAt = "2026-06-22 09:20"

  static var summary: String {
    "#\(commitCount) · \(commit) · \(builtAt)"
  }
}
